SELECT count(*) FROM name, cast_info, role_type, aka_name, char_name, title, movie_keyword, keyword, kind_type WHERE cast_info.person_id = name.id AND cast_info.role_id = role_type.id AND aka_name.person_id = name.id AND cast_info.person_role_id = char_name.id AND cast_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND title.kind_id = kind_type.id;